// // (1) disable: Disables the counter. Active low.
// (2) sync_reset: Synchronous reset of the counter. Active low.
// (3) neg_clk: Negative edge clock signal.
// (4) inverted_q: Inverted 7-bit output of the counter.
module top_module(
	input clk,
	input enable,
	input reset,
	output reg [6:0] q);always @(posedge clk or posedge reset) begin
	if (reset)
		q <= 7'b0000000;
	else if (enable)
		q <= q + 4;
end
endmodule

